import { createRoot } from 'react-dom/client';
import App from './App';

// Triggers the very first render
const root = createRoot(document.getElementById('root'));
root.render(<App />);

function Counter() {
  const [count, setCount] = useState(0);
  const [label, setLabel] = useState('');

  function handleClick() {
    setCount(c => c + 1); // batched
    setLabel('updated');  // batched — only ONE render fires
  }

  return <button onClick={handleClick}>{label}: {count}</button>;
}

// React calls your component like a function
// and stores the returned element tree
const elementTree = Counter({ count: 5 });
// elementTree = { type: 'button', props: { children: '5' }, ... }

// Conceptually (React does this internally):
// previousTree = { type: 'button', props: { children: '4' } }
// diff: update children from '4' to '5'

// WRONG — side effect in render
function BadComponent({ items }) {
  // This might run twice in StrictMode or be aborted in concurrent mode
  localStorage.setItem('items', JSON.stringify(items)); // mutation!
  return <ul>{items.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
}

// CORRECT — pure render, side effect in useEffect
function GoodComponent({ items }) {
  useEffect(() => {
    localStorage.setItem('items', JSON.stringify(items));
  }, [items]);
  return <ul>{items.map(i => <li key={i.id}>{i.name}</li>)}</ul>;
}

function Tooltip({ text, anchor }) {
  const ref = useRef(null);

  // useLayoutEffect fires after DOM update but BEFORE paint
  // Safe to measure DOM dimensions here
  useLayoutEffect(() => {
    const { bottom } = anchor.getBoundingClientRect();
    ref.current.style.top = `${bottom + 8}px`;
  }, [anchor]);

  return <div ref={ref} className="tooltip">{text}</div>;
}

// Order of events for a component mount:
// 1. Render (component function runs)
// 2. React commits DOM changes
// 3. useLayoutEffect setup runs (sync, before paint)
// 4. Browser paints
// 5. useEffect setup runs (async, after paint)

function Example() {
  useLayoutEffect(() => {
    console.log('3 — after DOM, before paint');
    return () => console.log('cleanup layout');
  }, []);

  useEffect(() => {
    console.log('5 — after paint');
    return () => console.log('cleanup effect');
  }, []);

  console.log('1 — render phase');
  return <div>Example</div>;
}

function ChatRoom({ roomId }) {
  useEffect(() => {
    const connection = createConnection(roomId);
    connection.connect();

    // Cleanup disconnects the OLD room before connecting to the NEW one
    return () => connection.disconnect();
  }, [roomId]); // runs every time roomId changes

  return <Chat room={roomId} />;
}

import { useTransition, useState } from 'react';

function SearchResults({ query }) {
  const [isPending, startTransition] = useTransition();
  const [results, setResults] = useState([]);

  function handleSearch(e) {
    // Mark the state update as low-priority (interruptible render)
    startTransition(() => {
      setResults(computeExpensiveResults(e.target.value));
    });
  }

  return (
    <>
      <input onChange={handleSearch} />
      {isPending ? <Spinner /> : <ResultList items={results} />}
    </>
  );
}

// Without memo: Row re-renders every time Parent re-renders
function Row({ item }) {
  return <li>{item.name}</li>;
}

// With memo: Row only re-renders if item prop changes
const Row = React.memo(function Row({ item }) {
  return <li>{item.name}</li>;
});

// Parent must stabilize the reference for memo to help
function List({ items }) {
  return (
    <ul>
      {items.map(item => (
        <Row key={item.id} item={item} />
      ))}
    </ul>
  );
}

// Render order for this tree:
// 1. App
// 2. Header
// 3. Nav (child of Header)
// 4. Main
// 5. Sidebar
// 6. Content

function App() {
  return (
    <>
      <Header />
      <Main />
    </>
  );
}
function Header() { return <nav><Nav /></nav>; }
function Main() { return <><Sidebar /><Content /></>; }

function UserProfile({ userId }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    let cancelled = false;
    fetch(`/api/users/${userId}`)
      .then(r => r.json())
      .then(data => {
        if (!cancelled) setUser(data); // triggers a new render cycle
      });
    return () => { cancelled = true; }; // cleanup if userId changes
  }, [userId]);

  if (!user) return <Spinner />;
  return <div>{user.name}</div>;
}
